import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  projectId: 'cs-flowise-support'
});

// In Flowise Custom Node
const chatflowCallback = async (input: any, output: any) => {
  const verification = await vex.verify({
    inputs: { query: input.query, docs: output.retrievedDocs },
    output: output.response,
    checks: ['semantic_similarity', 'response_accuracy'],
    threshold: 0.8
  });

  if (!verification.passed) {
    throw new Error(`Validation failed: ${verification.reason}`);
  }

  return output;
};

// Custom Tool Node with Vex PII Guard

const orderLookupTool = async (customerId: string) => {
  const orderData = await crmAPI.getOrder(customerId);

  const piiCheck = await vex.verify({
    inputs: { customerId },
    output: orderData,
    checks: ['pii_redaction'],
    rules: {
      redact: ['PHONE_NUMBER', 'EMAIL', 'SSN'],
      replace: '[REDACTED]'
    }
  });

  return {
    ...orderData,
    sanitized: piiCheck.output,
    piiDetected: piiCheck.detections
  };
};

const toneGuardrail = async (response: string, conversationHistory: any[]) => {
  const toneCheck = await vex.verify({
    inputs: { history: conversationHistory },
    output: response,
    checks: ['tone_consistency'],
    styleGuide: {
      company: 'support_brand',
      tone: 'empathetic_professional',
      avoid: ['sarcasm', 'jargon']
    }
  });

  return toneCheck.passed ? response : vex.suggestFix(toneCheck);
};

// Escalation Router Node
const escalationCheck = async (message: string, session: any) => {
  const analysis = await vex.analyze({
    text: message,
    context: session.history,
    checks: ['sentiment', 'escalation_triggers', 'policy_compliance']
  });

  return {
    needsEscalation: analysis.sentiment < -0.3 || analysis.violations.length > 0,
    reason: analysis.violations.join(', '),
    confidence: analysis.confidence
  };
};

