// flowise.config.ts
import { VexCallbackHandler } from '@vex_dev/sdk/flowise';

const vexHandler = new VexCallbackHandler({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'flowise-customer-support',
  riskProfile: 'high',
  defaultChecks: ['pii_redaction', 'response_accuracy', 'tone_consistency'],
  failureMode: 'block_and_log'
});

// Add to Flowise chatflow configuration
export const chatflowConfig = {
  callbacks: [vexHandler],
  nodes: {
    ragChain: { postProcess: vexHandler.verify },
    toolAgent: { preExecute: vexHandler.validateInputs }
  }
};

// vex-guard-node.ts (Flowise Custom Node)
import { BaseChatModel } from '@langchain/core/language_models/chat_models';

export class VexGuardNode {
  async invoke(input: any, vexClient: any) {
    const result = await vexClient.verify({
      inputs: input,
      checks: ['factual_consistency', 'policy_compliance'],
      contextWindow: input.conversationHistory
    });

    return {
      ...input,
      verified: result.passed,
      score: result.score,
      issues: result.issues
    };
  }
}

// Session monitoring middleware
const sessionMonitor = {
  init: (sessionId: string) => {
    return vex.session.start({
      sessionId,
      useCase: 'customer_support',
      riskProfile: 'high',
      track: ['pii_exposure', 'escalation_risk', 'accuracy_drift']
    });
  },

  logTurn: async (sessionId: string, turnData: any) => {
    await vex.session.logTurn(sessionId, {
      userInput: turnData.query,
      aiOutput: turnData.response,
      metadata: { agent: 'support_rag', tools_used: turnData.tools }
    });

    const riskScore = await vex.session.riskScore(sessionId);
    return riskScore > 0.7; // Trigger human review
  }
};
